INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (1, 101831, 312, "", "", "", 3, "nop_talk_joy1", 312002, 0.2, "");
