INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (1, 101611, 312, "", "", "", 3, "nop_talk_surprise_kira", 312006, 0.2, "");
