INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (8, 105011, 312, 0, 0, 0.5, 11, "えー？　でもあれって野菜じゃない？\n別に、大人のレディだから\n食べられないわけじゃないけど？", 312009, 0, 0);
INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (1, 105011, 312, "", "", "", 3, "nop_talk_sad", 312010, 0.2, "");
