INSERT INTO `v1_8663bfe9931762fe6d3f8940de6ee71235cbbcb84d4e59b1ab4498867e17ca11` VALUES (1, 100811, 513, "", "", "", 3, "nop_talk_thinking", 513044, 0.2, "");
